import { useState } from "react";
import LandingPage from "./components/LandingPage"; // ou ./pages/LandingPage
import ScheduleSystem from "./AppContent"; // O código que tínhamos antes

export default function App() {
  const [view, setView] = useState("landing"); // 'landing' ou 'schedule'

  return (
    <div>
      {view === "landing" ? (
        // Passamos uma função para o botão "Agende Aqui" mudar a tela
        <LandingPage onNavigate={() => setView("schedule")} />
      ) : (
        <div className="relative">
           <button 
             onClick={() => setView("landing")}
             className="fixed top-4 left-4 z-[100] bg-pbYellow text-black px-4 py-2 rounded font-bold"
           >
             ← Voltar
           </button>
           {/* Aqui vai todo aquele código do sistema de agendamento que já fizemos */}
           <Navbar />
           <Hero />
           {/* ... etc */}
        </div>
      )}
    </div>
  );
}
